const items = $input.all();

const tickets = items.map((item, index) => {
  const t = item.json;

  const isEmpty =
    (String(t.body || '').trim().length < 5);

  return {
    index,
    ticket_id: t.ticket_id || String(index + 1),
    created_at: t.created_at || '',
    customer_name: t.customer_name || '',
    customer_email: t.customer_email || '',
    subject: t.subject || '',
    body: t.body || '',
    status: t.status || '',
    _skip: isEmpty,
    _fallback_reason: isEmpty ? 'empty_ticket' : ''
  };
});

const ticketsForLLM = tickets
  .filter(t => !t._skip)
  .map(t => ({
    index: t.index,
    ticket_id: t.ticket_id,
    subject: t.subject,
    body: t.body,
    customer_name: t.customer_name,
    customer_email: t.customer_email
  }));

// Prevents 400 Bad Request when a batch contains 100% skipped/empty tickets
if (ticketsForLLM.length === 0) {
  return [{
    json: {
      batchTickets: tickets,
      skipGemini: true,
      requestBody: {
        contents: [
          {
            parts: [
              { text: "Return an empty array: []" }
            ]
          }
        ],
        generationConfig: {
          temperature: 0.1,
          maxOutputTokens: 10,
          responseMimeType: "application/json"
        }
      }
    }
  }];
}

const prompt = `You are an expert support ticket triage analyst for AU10TIX, an identity verification and fraud prevention company.
Classify each ticket in the JSON array independently. Return one object per ticket with the same index and ticket_id. Use only subject/body facts.

CATEGORY (if multiple, pick highest):
1. Fraud Concern - forged/tampered docs, stolen identity, impersonation, unauthorized account, suspicious patterns
2. Account Access - login, password, 2FA, lockout, deactivated account
3. Document Issue - upload/OCR/reject/format issues, verification mismatch, customer is verifying their own account
4. Billing - invoices, charges, refunds, subscriptions
5. General Inquiry - product/API/how-to/partnerships

Document Issue vs Fraud Concern: technical upload/OCR/format problems → Document Issue. Claims of misuse, "not me", wrong person on ID → Fraud Concern.

URGENCY (ignore age/status):
High = fraud/security, blocked verification, account takeover
Medium = verification/access/billing issues
Low = general questions, routine requests, minor/unclear non-urgent issues

flag_for_review:
Set to true only for clear fraud/security (fake/forged docs, stolen identity, impersonation, unauthorized use, suspicious multi-account patterns).
Otherwise false.

summary:
Write one short plain-English sentence describing the customer's issue. No category names, no error codes.

Return ONLY a valid JSON array.
Do not add markdown, explanations, or extra text.

Tickets JSON:
${JSON.stringify(ticketsForLLM)}`;

return [{
  json: {
    batchTickets: tickets,
    skipGemini: false,
    requestBody: {
      contents: [
        {
          parts: [
            { text: prompt }
          ]
        }
      ],
      generationConfig: {
        temperature: 0.1,
        maxOutputTokens: 1000,
        responseMimeType: "application/json",
        responseSchema: {
          type: "ARRAY",
          description: "An array containing the classification results for each ticket.",
          items: {
            type: "OBJECT",
            properties: {
              index: { type: "INTEGER" },
              ticket_id: { type: "STRING" },
              urgency: { type: "STRING", enum: ["High", "Medium", "Low"] },
              category: { type: "STRING", enum: ["Document Issue", "Account Access", "Billing", "Fraud Concern", "General Inquiry"] },
              summary: { type: "STRING" },
              flag_for_review: { type: "BOOLEAN" }
            },
            required: ["index", "ticket_id", "urgency", "category", "summary", "flag_for_review"]
          }
        }
      }
    }
  }
}];

const item = $input.item.json;
const originalBatch = $('Build Gemini Batch').item.json.batchTickets || [];

const VALID_URGENCY = ['High', 'Medium', 'Low'];
const VALID_CATEGORY = [
  'Document Issue',
  'Account Access',
  'Billing',
  'Fraud Concern',
  'General Inquiry'
];

function fallbackFor(ticket, reason) {
  let summary = 'LLM returned an invalid response format, so classification was replaced with a safe fallback.';

  if (reason === 'empty_ticket') {
    summary = 'No classification was needed because the ticket subject and body are empty or unreadable.';
  }

  if (reason === 'missing_llm_result') {
    summary = 'LLM did not return a classification for this ticket, so a safe fallback was used.';
  }

  return {
    ...ticket,
    urgency: 'Low',
    category: 'General Inquiry',
    summary,
    flag_for_review: false,
    _fallback_reason: reason
  };
}

function normalize(ticket, parsed) {
  return {
    ...ticket,
    urgency: VALID_URGENCY.includes(parsed.urgency) ? parsed.urgency : 'Low',
    category: VALID_CATEGORY.includes(parsed.category) ? parsed.category : 'General Inquiry',
    summary: (parsed.summary || 'No summary provided.').substring(0, 200),
    flag_for_review:
      typeof parsed.flag_for_review === 'boolean'
        ? parsed.flag_for_review
        : String(parsed.flag_for_review).toLowerCase() === 'true',
    _fallback_reason: ''
  };
}

try {
  let raw = item.candidates?.[0]?.content?.parts?.[0]?.text || '';

  const startIdx = raw.indexOf('[');
  const endIdx = raw.lastIndexOf(']');

  if (startIdx === -1 || endIdx === -1 || endIdx < startIdx) {
    throw new Error('No JSON array found');
  }

  const cleanedJson = raw.substring(startIdx, endIdx + 1);
  const parsedArray = JSON.parse(cleanedJson);
  if (!Array.isArray(parsedArray)) {
    throw new Error('Parsed response is not an array');
  }

  const byIndex = new Map();
  const byTicketId = new Map();

  for (const result of parsedArray) {
    if (result.index !== undefined) {
      byIndex.set(Number(result.index), result);
    }

    if (result.ticket_id !== undefined) {
      byTicketId.set(String(result.ticket_id), result);
    }
  }

  return originalBatch.map((ticket) => {
    if (ticket._skip) {
      return { json: fallbackFor(ticket, 'empty_ticket') };
    }

    const result =
      byIndex.get(Number(ticket.index)) ||
      byTicketId.get(String(ticket.ticket_id));

    if (!result) {
      return { json: fallbackFor(ticket, 'missing_llm_result') };
    }

    return { json: normalize(ticket, result) };
  });
} catch (e) {
  return originalBatch.map((ticket) => {
    const reason = ticket._skip ? 'empty_ticket' : 'invalid_llm_response';
    return { json: fallbackFor(ticket, reason) };
  });
}

const originalBatch = $('Build Gemini Batch').item.json.batchTickets || [];

const errorMessage =
  $json.error?.message ||
  $json.message ||
  JSON.stringify($json);

function getApiFallback() {
  if (errorMessage.includes('429')) {
    return {
      reason: 'rate_limit_failure',
      summary: 'Gemini API rate limit prevented LLM classification.'
    };
  }

  if (errorMessage.includes('503') || errorMessage.toLowerCase().includes('unavailable')) {
    return {
      reason: 'model_unavailable',
      summary: 'Gemini model was temporarily unavailable, so a safe fallback classification was used.'
    };
  }

  if (
    errorMessage.toLowerCase().includes('timeout') ||
    errorMessage.toLowerCase().includes('timed out') ||
    errorMessage.toLowerCase().includes('etimedout')
  ) {
    return {
      reason: 'timeout_failure',
      summary: 'Gemini API request timed out, so a safe fallback classification was used.'
    };
  }

  return {
    reason: 'api_or_request_failure',
    summary: 'Gemini API request failed, so a safe fallback classification was used.'
  };
}

const apiFallback = getApiFallback();

return originalBatch.map((ticket) => {
  if (ticket._skip) {
    return {
      json: {
        ...ticket,
        urgency: 'Low',
        category: 'General Inquiry',
        summary: 'No classification was needed because the ticket subject and body are empty or unreadable.',
        flag_for_review: false,
        _fallback_reason: 'empty_ticket'
      }
    };
  }

  return {
    json: {
      ...ticket,
      urgency: 'Low',
      category: 'General Inquiry',
      summary: apiFallback.summary,
      flag_for_review: false,
      _fallback_reason: apiFallback.reason
    }
  };
});

const ticket = $input.item.json;

const textToCheck = `${ticket.subject || ''} ${ticket.body || ''}`
  .toLowerCase()
  .replace(/[^\w\s']/g, ' ');

const fraudPatterns = [
  /\b(forged|forgery|fake id|fake document|fake passport|counterfeit|altered document|doctored|tampered|photoshopped)\b/i,

  /\b(stolen identity|identity theft|my identity was stolen|stole my identity)\b/i,

  /\b(impersonat\w*|account takeover|compromised account|hijacked)\b/i,

  /\b(unauthorized account|unauthorized access|without my permission)\b/i,

  /\b(not mine|not my account|this wasn't me|this was not me)\b/i,

  /\b(my id was used|id was used|used my documents|using my documents)\b/i,

  /\b(opened an account in my name|account created in my name)\b/i,

  /\b(i did not create this account|i didn't create this account)\b/i,

  /\b(someone else is using|someone else used|someone pretending to be me)\b/i,

  /\b(bypass kyc|bypass verification|disable verification)\b/i,

  /\b(suspicious account|suspicious activity|suspicious verification|flag suspicious|looks suspicious|fraudulent|possible fraud|report fraud|fraud attempt)\b/i,
];

const normalMismatchPattern =
  /\b(middle name|name mismatch|passport mismatch|date of birth|dob mismatch|account information|verification mismatch|does not match|doesn't match)\b/i;

const strongFraudPattern =
  /\b(forged|fake|tampered|stolen identity|identity theft|impersonat\w*|unauthorized|without my permission|not mine|wasn't me|was not me|someone else|suspicious account|suspicious activity|suspicious verification|fraudulent|possible fraud|report fraud|fraud attempt)\b/i;

const isNormalMismatch =
  normalMismatchPattern.test(textToCheck) &&
  !strongFraudPattern.test(textToCheck);

let localFraudDetected = false;

if (!isNormalMismatch) {
  for (const pattern of fraudPatterns) {
    if (pattern.test(textToCheck)) {
      localFraudDetected = true;
      break;
    }
  }
}

if (localFraudDetected) {
  ticket.category = 'Fraud Concern';
  ticket.flag_for_review = true;
  ticket.urgency = 'High';
}

if (localFraudDetected && ticket._fallback_reason === 'empty_ticket') {
  ticket.summary =
    'The ticket message was empty, but rule-based checks detected possible fraud indicators.';
} else if (localFraudDetected && ticket._fallback_reason) {
  ticket.summary =
    'AI classification was unavailable, but rule-based checks detected possible fraud indicators.';
}

return { json: ticket };

const items = $input.all();

return items.map((item) => {
  const j = { ...item.json };

  delete j.index;
  delete j._skip;
  delete j._fallback_reason;

  return { json: j };
});

function escapeCSV(value) {
  if (value === null || value === undefined) {
    return '';
  }

  let s = String(value);

    // Security Gate: Neutralize leading formula characters (CSV Formula Injection Preventative Defense)
    if (s.startsWith('=') || s.startsWith('+') || s.startsWith('-') || s.startsWith('@')) {
    s = "'" + s;
  }

  if (
    s.includes(',') ||
    s.includes('"') ||
    s.includes('\n') ||
    s.includes('\r')
  ) {
    return '"' + s.replace(/"/g, '""') + '"';
  }

  return s;
}

const items = $input.all();

const headers = [
  'ticket_id',
  'created_at',
  'customer_name',
  'customer_email',
  'subject',
  'body',
  'status',
  'urgency',
  'category',
  'summary',
  'flag_for_review'
];

let csvContent = headers.join(',') + '\n';

for (const item of items) {
  const row = headers.map((h) => escapeCSV(item.json[h]));
  csvContent += row.join(',') + '\n';
}

return [
  {
    json: {
      csvContent,
      ticketCount: items.length
    }
  }
];

const csvContent = $input.first().json.csvContent;
const ticketCount = $input.first().json.ticketCount;

const binaryData = Buffer.from(csvContent).toString('base64');

return [
  {
    json: {
      ticketCount,
      message: `CSV file generated with ${ticketCount} ticket(s)`
    },
    binary: {
      data: {
        data: binaryData,
        mimeType: 'text/csv',
        fileName: 'classified_tickets.csv'
      }
    }
  }
];
